CREATE TABLE governance_policies_v3(policy_version TEXT PRIMARY KEY,policy_checksum TEXT NOT NULL CHECK(length(policy_checksum)=64),policy JSONB NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE research_datasets_v3(dataset_id UUID PRIMARY KEY,dataset_version TEXT NOT NULL UNIQUE,dataset_checksum TEXT NOT NULL CHECK(length(dataset_checksum)=64),source_versions JSONB NOT NULL,train_start DATE,train_end DATE,validation_start DATE,validation_end DATE,calibration_start DATE,calibration_end DATE,test_start DATE NOT NULL,test_end DATE NOT NULL,purge_days INTEGER NOT NULL,embargo_days INTEGER NOT NULL,lineage JSONB NOT NULL,reproducibility JSONB NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE governed_models_v3(model_id UUID PRIMARY KEY,model_version TEXT NOT NULL UNIQUE,model_type TEXT NOT NULL,definition_checksum TEXT NOT NULL CHECK(length(definition_checksum)=64),artifact_checksum TEXT CHECK(artifact_checksum IS NULL OR length(artifact_checksum)=64),configuration JSONB NOT NULL,source_lineage JSONB NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE research_experiments_v3(experiment_id UUID PRIMARY KEY,experiment_version TEXT NOT NULL UNIQUE,definition_checksum TEXT NOT NULL CHECK(length(definition_checksum)=64),dataset_id UUID NOT NULL REFERENCES research_datasets_v3(dataset_id),champion_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),challenger_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),hypothesis TEXT NOT NULL,evaluation_plan JSONB NOT NULL,reproducibility JSONB NOT NULL,created_at TIMESTAMP NOT NULL,CHECK(champion_model_id<>challenger_model_id));
CREATE TABLE research_experiment_runs_v3(run_id UUID PRIMARY KEY,experiment_id UUID NOT NULL REFERENCES research_experiments_v3(experiment_id),cutoff_at TIMESTAMP NOT NULL,state TEXT NOT NULL CHECK(state IN ('PASS','FAIL','INSUFFICIENT_EVIDENCE')),observation_count INTEGER NOT NULL,test_count INTEGER NOT NULL,excluded_count INTEGER NOT NULL,replay_checksum TEXT NOT NULL CHECK(length(replay_checksum)=64),started_at TIMESTAMP NOT NULL,completed_at TIMESTAMP NOT NULL,UNIQUE(experiment_id,cutoff_at,replay_checksum));
CREATE TABLE research_replay_observations_v3(run_id UUID NOT NULL REFERENCES research_experiment_runs_v3(run_id),observation_id TEXT NOT NULL,period_name TEXT NOT NULL,included BOOLEAN NOT NULL,exclusion_reason TEXT,terminal_at TIMESTAMP,champion_return NUMERIC,challenger_return NUMERIC,source_lineage JSONB NOT NULL,PRIMARY KEY(run_id,observation_id));
CREATE TABLE model_comparisons_v3(comparison_id UUID PRIMARY KEY,run_id UUID NOT NULL REFERENCES research_experiment_runs_v3(run_id),champion_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),challenger_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),sample_size INTEGER NOT NULL,mean_champion_return NUMERIC,mean_challenger_return NUMERIC,mean_difference NUMERIC,confidence_low NUMERIC,confidence_high NUMERIC,test_statistic NUMERIC,p_value NUMERIC,adjusted_alpha NUMERIC,effect_size NUMERIC,superiority_state TEXT NOT NULL CHECK(superiority_state IN ('SUPERIOR','NOT_SUPERIOR','INSUFFICIENT_EVIDENCE')),lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(run_id,champion_model_id,challenger_model_id));
CREATE TABLE research_evaluation_reports_v3(report_id UUID PRIMARY KEY,run_id UUID NOT NULL REFERENCES research_experiment_runs_v3(run_id),report_version TEXT NOT NULL,metrics JSONB NOT NULL,audits JSONB NOT NULL,multiple_testing JSONB NOT NULL,reproducibility JSONB NOT NULL,promotion_eligible BOOLEAN NOT NULL,limitations JSONB NOT NULL,report_checksum TEXT NOT NULL CHECK(length(report_checksum)=64),created_at TIMESTAMP NOT NULL,UNIQUE(run_id,report_version));
CREATE TABLE model_promotion_proposals_v3(proposal_id UUID PRIMARY KEY,report_id UUID NOT NULL REFERENCES research_evaluation_reports_v3(report_id),challenger_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),current_champion_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),policy_version TEXT NOT NULL REFERENCES governance_policies_v3(policy_version),shadow_session_count INTEGER NOT NULL,proposal_checksum TEXT NOT NULL CHECK(length(proposal_checksum)=64),created_at TIMESTAMP NOT NULL);
CREATE TABLE governance_approvals_v3(approval_id UUID PRIMARY KEY,proposal_id UUID NOT NULL REFERENCES model_promotion_proposals_v3(proposal_id),approval_role TEXT NOT NULL CHECK(approval_role IN ('RESEARCH_OWNER','RISK_OWNER','DATA_OWNER')),approver_id TEXT NOT NULL,decision TEXT NOT NULL CHECK(decision IN ('APPROVE','REJECT')),rationale TEXT NOT NULL,approved_at TIMESTAMP NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(proposal_id,approval_role,approver_id));
CREATE TABLE model_promotion_decisions_v3(decision_id UUID PRIMARY KEY,proposal_id UUID NOT NULL UNIQUE REFERENCES model_promotion_proposals_v3(proposal_id),state TEXT NOT NULL CHECK(state IN ('APPROVED','REJECTED')),reason TEXT NOT NULL,approval_count INTEGER NOT NULL,readiness_passed BOOLEAN NOT NULL,decided_at TIMESTAMP NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64));
CREATE TABLE model_role_assignments_v3(assignment_id UUID PRIMARY KEY,model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),role TEXT NOT NULL CHECK(role IN ('CHAMPION','CHALLENGER','RETIRED')),effective_at TIMESTAMP NOT NULL,source_decision_id UUID REFERENCES model_promotion_decisions_v3(decision_id),previous_assignment_id UUID REFERENCES model_role_assignments_v3(assignment_id),lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64));
CREATE TABLE model_rollback_metadata_v3(rollback_id UUID PRIMARY KEY,promotion_decision_id UUID NOT NULL REFERENCES model_promotion_decisions_v3(decision_id),from_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),to_model_id UUID NOT NULL REFERENCES governed_models_v3(model_id),trigger_condition TEXT NOT NULL,rollback_procedure JSONB NOT NULL,state TEXT NOT NULL CHECK(state IN ('PLANNED','REVIEW_REQUIRED')),created_at TIMESTAMP NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64));
CREATE TABLE governance_audit_history_v3(audit_id UUID PRIMARY KEY,entity_type TEXT NOT NULL,entity_id UUID NOT NULL,event_type TEXT NOT NULL,event_at TIMESTAMP NOT NULL,actor_type TEXT NOT NULL CHECK(actor_type IN ('OFFLINE_SERVICE','HUMAN_APPROVER')),details JSONB NOT NULL,previous_audit_id UUID REFERENCES governance_audit_history_v3(audit_id),lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(entity_type,entity_id,event_type,lineage_checksum));
CREATE FUNCTION reject_governance_v3_mutation() RETURNS trigger AS $$ BEGIN RAISE EXCEPTION 'Institutional research governance evidence is immutable'; END; $$ LANGUAGE plpgsql;
DO $$ DECLARE t TEXT; BEGIN FOREACH t IN ARRAY ARRAY['governance_policies_v3','research_datasets_v3','governed_models_v3','research_experiments_v3','research_experiment_runs_v3','research_replay_observations_v3','model_comparisons_v3','research_evaluation_reports_v3','model_promotion_proposals_v3','governance_approvals_v3','model_promotion_decisions_v3','model_role_assignments_v3','model_rollback_metadata_v3','governance_audit_history_v3'] LOOP EXECUTE format('CREATE TRIGGER %I_immutable BEFORE UPDATE OR DELETE ON %I FOR EACH ROW EXECUTE FUNCTION reject_governance_v3_mutation()',t,t); END LOOP; END $$;
